import React, { useState, useRef } from 'react';
import { MicrophoneIcon, SearchIcon } from './AppIcons';

interface SearchFormProps {
    onSearch: (query: string) => void;
    disabled?: boolean;
}

const SearchForm: React.FC<SearchFormProps> = ({ onSearch, disabled = false }) => {
    const [query, setQuery] = useState('');
    const [isListening, setIsListening] = useState(false);
    const recognitionRef = useRef<any>(null);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (query.trim()) {
            onSearch(query.trim());
        }
    };

    const playTone = (frequency: number, duration: number) => {
        try {
            const audioCtx = new ((window as any).AudioContext || (window as any).webkitAudioContext)();
            if (!audioCtx) return;

            const oscillator = audioCtx.createOscillator();
            const gainNode = audioCtx.createGain();

            oscillator.connect(gainNode);
            gainNode.connect(audioCtx.destination);

            oscillator.type = 'sine';
            oscillator.frequency.setValueAtTime(frequency, audioCtx.currentTime);

            gainNode.gain.setValueAtTime(0.2, audioCtx.currentTime);
            gainNode.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + duration);

            oscillator.start(audioCtx.currentTime);
            oscillator.stop(audioCtx.currentTime + duration);
        } catch (e) {
            console.error("Web Audio API error:", e);
        }
    };

    const handleVoiceSearch = async () => {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("عذراً، البحث الصوتي غير مدعوم في متصفحك.");
            return;
        }

        if (isListening) {
            recognitionRef.current?.stop();
            return;
        }

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            stream.getTracks().forEach(track => track.stop());
        } catch (err: any) {
            console.error("Microphone permission error", err);
            if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
                 alert("للبحث الصوتي، يرجى السماح بالوصول إلى الميكروفون في إعدادات متصفحك أو عند الطلب.");
            } else {
                 alert("لم يتم العثور على ميكروفون أو حدث خطأ عند محاولة الوصول إليه.");
            }
            return;
        }

        playTone(880, 0.15);

        const recognition = new SpeechRecognition();
        recognition.lang = 'ar-SA';
        recognition.continuous = false;
        recognition.interimResults = false;
        recognitionRef.current = recognition;

        recognition.onstart = () => {
            setIsListening(true);
        };

        recognition.onresult = (event: any) => {
            let transcript = event.results[0][0].transcript;
            transcript = transcript.replace(/[.?!؟,]/g, '').trim();
            setQuery(transcript);
            onSearch(transcript);
        };

        recognition.onerror = (event: any) => {
            console.error("Speech recognition error", event.error);
            if (event.error !== 'not-allowed' && event.error !== 'service-not-allowed' && event.error !== 'no-speech') {
                 alert("حدث خطأ أثناء التعرف على الصوت.");
            }
        };

        recognition.onend = () => {
            playTone(523, 0.2);
            setIsListening(false);
            recognitionRef.current = null;
        };

        recognition.start();
    };

    return (
        <form onSubmit={handleSubmit} className="flex-grow w-full max-w-xl">
            <div className="relative">
                <input
                    type="search"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={disabled ? "جاري تحميل بيانات البحث..." : "ابحث عن كلمة، أو أدخل مرجعاً مثل (البقرة ٢٥٥)..."}
                    className="w-full text-base py-2 pl-14 pr-4 bg-surface border-2 border-transparent rounded-full focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all disabled:opacity-70 disabled:cursor-not-allowed"
                    aria-label="بحث في المصحف الشريف"
                    disabled={disabled}
                />
                <div className="absolute left-3 top-1/2 -translate-y-1/2 flex items-center gap-1">
                    <button type="button" onClick={handleVoiceSearch} className={`p-1 text-text-subtle rounded-full ${isListening ? 'text-red-500 animate-pulse-mic' : 'hover:text-primary'} disabled:opacity-50 disabled:cursor-not-allowed`} aria-label="بحث صوتي" title="بحث صوتي" disabled={disabled}>
                        <MicrophoneIcon className="w-4 h-4" />
                    </button>
                    <button type="submit" className="p-1 text-text-subtle hover:text-primary disabled:opacity-50 disabled:cursor-not-allowed" aria-label="بحث" disabled={disabled}>
                        <SearchIcon className="w-4 h-4" />
                    </button>
                </div>
            </div>
        </form>
    );
};

export default SearchForm;

import React, { useRef, useEffect } from 'react';
import type { Ayah, QuranEdition } from '../types';
import { PlayIcon, PauseIcon, ForwardIcon, BackwardIcon, XIcon, SpinnerIcon } from './AppIcons';

interface AudioPlayerBarProps {
    playlist: Ayah[];
    currentIndex: number;
    isPlaying: boolean;
    isLoading: boolean;
    onPlayPause: () => void;
    onNext: () => void;
    onPrev: () => void;
    onEnded: () => void;
    onClose: () => void;
    audioEdition: QuranEdition | undefined;
}

const AudioPlayerBar: React.FC<AudioPlayerBarProps> = ({ playlist, currentIndex, isPlaying, isLoading, onPlayPause, onNext, onPrev, onEnded, onClose, audioEdition }) => {
    const audioRef = useRef<HTMLAudioElement>(null);
    const currentAyah = playlist[currentIndex];

    useEffect(() => {
        const audio = audioRef.current;
        if (!audio || !currentAyah?.audio) return;

        // Only update src if it's different to prevent re-loading the same track
        // We also check against the potential fallback logic (currentAyah.audio or currentAyah.audioSecondary[0])
        const currentSrc = audio.getAttribute('src');
        const primarySrc = currentAyah.audio;

        // If currentSrc is not the primary and not the secondary (if exists), then we should load primary.
        // But if currentSrc is already the secondary (due to fallback), we shouldn't force primary unless index changed.

        // Simpler check: If index changed, we must load primary.
        // We rely on 'currentIndex' dependency.

        // When index changes, force primary
        audio.src = primarySrc;

        if (isPlaying) {
            audio.play().catch(e => console.error("Audio play failed:", e));
        } else {
            audio.pause();
        }
    }, [currentIndex, isPlaying, playlist, currentAyah]);

    useEffect(() => {
        const audio = audioRef.current;
        if (audio) {
            audio.addEventListener('ended', onEnded);
            return () => {
                audio.removeEventListener('ended', onEnded);
            };
        }
    }, [onEnded]);

    const handleAudioError = () => {
        if (audioRef.current && currentAyah?.audioSecondary && currentAyah.audioSecondary.length > 0) {
            const fallbackUrl = currentAyah.audioSecondary[0];
            const currentSrc = audioRef.current.getAttribute('src');

            // If we haven't tried the fallback yet (or current src is different from fallback)
            if (currentSrc !== fallbackUrl) {
                console.log("Audio playback failed. Switching to fallback source...");
                audioRef.current.src = fallbackUrl;
                if (isPlaying) {
                    audioRef.current.play().catch(e => console.error("Fallback play failed:", e));
                }
                return;
            }
        }
        console.error("Audio playback error (all sources failed).");
    };

    const getSurahName = () => {
        if (!currentAyah?.surah?.name) return '...';
        return currentAyah.surah.name.replace(/^سُورَةُ\s*/, '').trim();
    }

    const getTitle = () => {
        if (isLoading) return 'جاري التحضير...';
        const reciterName = audioEdition?.name ? `${audioEdition.name} - ` : '';
        return `${reciterName}سورة ${getSurahName()}`;
    };

    return (
        <div className="fixed bottom-0 left-0 right-0 bg-surface/90 backdrop-blur-md z-40 shadow-[0_-4px_30px_rgba(0,0,0,0.1)] animate-fade-in">
            <audio ref={audioRef} preload="auto" onError={handleAudioError} />
            <div className="max-w-4xl mx-auto p-3 flex items-center justify-between gap-4">
                <div className="flex-grow min-w-0">
                    <p className="font-bold text-text-primary truncate">
                       { getTitle() }
                    </p>
                    <p className="text-sm text-text-muted">
                       { !isLoading && `الآية ${currentAyah?.numberInSurah}` }
                    </p>
                </div>
                <div className="flex items-center gap-2 sm:gap-4 flex-shrink-0">
                    <button onClick={onPrev} disabled={isLoading} className="p-2 text-text-secondary hover:text-text-primary transition-colors disabled:opacity-50">
                        <BackwardIcon className="w-6 h-6" />
                    </button>
                    <button onClick={onPlayPause} disabled={isLoading} className="p-3 bg-primary text-white rounded-full shadow-lg hover:bg-primary-hover transition-transform hover:scale-105 disabled:bg-primary/60">
                        {isLoading ? <SpinnerIcon className="w-7 h-7" /> : (
                            isPlaying ? <PauseIcon className="w-7 h-7" /> : <PlayIcon className="w-7 h-7" />
                        )}
                    </button>
                    <button onClick={onNext} disabled={isLoading} className="p-2 text-text-secondary hover:text-text-primary transition-colors disabled:opacity-50">
                        <ForwardIcon className="w-6 h-6" />
                    </button>
                </div>
                 <div className="flex-grow text-left">
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-surface-subtle">
                        <XIcon className="w-6 h-6 text-text-subtle" />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default AudioPlayerBar;

import React, { useMemo } from 'react';
import type { Ayah, SurahData, QuranEdition, FontSize, FontStyleType } from '../types';
import { SparklesIcon } from './AppIcons';
import { normalizeArabicText } from '../utils/text';

interface SearchResultItemProps {
  ayah: Ayah;
  queryWords: string[];
  onNewSearch: (word: string, sourceEdition?: string, position?: { surah: number, ayah: number, wordIndex: number }) => void;
  displayEdition: QuranEdition;
  displayEditionData: SurahData[];
  searchEdition: string;
  fontSize: FontSize;
  fontStyle: FontStyleType;
  searchType: 'text' | 'number';
  isCurrentlyPlaying: boolean;
  itemRef: React.RefObject<HTMLLIElement>;
  pulsingWordIndex: number;
  resultIndex: number;
  simpleAyahText: string;
  onUthmaniWordClick: (event: React.MouseEvent<HTMLButtonElement>, resultIndex: number, simpleAyahText: string) => void;
  onOpenPopover: (ayah: Ayah, triggerElement: HTMLElement) => void;
}

const SearchResultItem: React.FC<SearchResultItemProps> = ({ 
    ayah, queryWords, onNewSearch, displayEdition, displayEditionData, 
    fontSize, fontStyle, searchType, isCurrentlyPlaying, itemRef, pulsingWordIndex,
    resultIndex, simpleAyahText, onUthmaniWordClick, onOpenPopover
}) => {

    const displayAyah = useMemo(() => {
        if (displayEditionData?.length > 0 && ayah.surah) {
            const displaySurah = displayEditionData.find(s => s.number === ayah.surah!.number);
            const displayAyahData = displaySurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
            if (displayAyahData && displaySurah) {
                return { 
                    ...displayAyahData,
                    surah: {
                        number: displaySurah.number,
                        name: displaySurah.name,
                        englishName: displaySurah.englishName,
                        englishNameTranslation: displaySurah.englishNameTranslation,
                        revelationType: displaySurah.revelationType,
                    }
                };
            }
        }
        return ayah;
    }, [ayah, displayEditionData]);

    const handleSelectResult = (e: React.MouseEvent<HTMLAnchorElement>) => {
        e.preventDefault();
        if(ayah.surah) {
            window.location.hash = e.currentTarget.getAttribute('href')!;
        }
    };

    const getQuranTextStyle = () => {
        // Force Uthmani font regardless of fontStyle setting to ensure consistency
        return {
            className: `uthmani-font quran-text-${fontSize}`,
        };
    };

    const { className: quranTextClass } = getQuranTextStyle();

    const renderAyahWithHighlight = () => {
        if (displayEdition.format === 'audio') {
            return <span className="text-sm text-text-muted">[مصدر صوتي، لا يتوفر عرض نصي هنا]</span>
        }

        if (!displayAyah.text) {
            return '';
        }
        const textToRender = displayAyah.text;
        const isImlaei = displayEdition.identifier.includes('simple-clean');

        const wordElements = textToRender.split(' ').map((word, index) => {
            const isPulsing = index === pulsingWordIndex;

            if (searchType === 'number') { // No highlighting for number search
                 return (
                    <button 
                        type="button" 
                        key={index} 
                        onClick={(e) => {
                            e.stopPropagation();
                            if (isImlaei) {
                                if (word && ayah.surah) {
                                    onNewSearch(word, displayEdition.identifier, { surah: ayah.surah.number, ayah: ayah.numberInSurah, wordIndex: index });
                                }
                            } else {
                                if (simpleAyahText) {
                                    onUthmaniWordClick(e, resultIndex, simpleAyahText);
                                }
                            }
                        }} 
                        className="word-trigger bg-transparent border-none p-0 font-inherit cursor-pointer hover:bg-primary/10 rounded-md px-1 transition-colors"
                        aria-label={`إظهار خيارات البحث لكلمة: ${word}`}
                    >
                        <span className={isPulsing ? 'animate-highlight-pulse rounded-sm' : ''}>{word}</span>
                    </button>
                 );
            }

            const normalizedWord = normalizeArabicText(word);
            const isMatch = queryWords.some(queryWord => normalizedWord.includes(queryWord));

            return (
                <button
                    type="button"
                    key={index}
                    onClick={(e) => {
                        e.stopPropagation();
                        if (isImlaei) {
                            if (word && ayah.surah) {
                                onNewSearch(word, displayEdition.identifier, { surah: ayah.surah.number, ayah: ayah.numberInSurah, wordIndex: index });
                            }
                        } else {
                            if (simpleAyahText) {
                                onUthmaniWordClick(e, resultIndex, simpleAyahText);
                            }
                        }
                    }}
                    className="word-trigger bg-transparent border-none p-0 font-inherit cursor-pointer hover:bg-primary/10 rounded-md px-1 transition-colors"
                    aria-label={`إظهار خيارات البحث لكلمة: ${word}`}
                >
                    {isMatch ? (
                        <mark className={`bg-yellow-400/40 text-text-primary rounded-sm ${isPulsing ? 'animate-highlight-pulse' : ''}`}>{word}</mark>
                    ) : (
                        <span className={isPulsing ? 'animate-highlight-pulse rounded-sm' : ''}>{word}</span>
                    )}
                </button>
            );
        });

        return wordElements.reduce((prev, curr, index) => <>{prev}{index > 0 ? ' ' : ''}{curr}</>, <></>);
    };

    return (
        <li
            ref={itemRef}
            className={`p-4 rounded-xl shadow-sm transition-all duration-300 hover:shadow-lg ${isCurrentlyPlaying ? 'bg-primary/20 ring-2 ring-primary' : 'bg-surface-subtle'}`}
        >
            <div className="flex justify-between items-center mb-2 gap-4">
                 <a
                    href={`#/surah/${displayAyah.surah?.number}?ayah=${displayAyah.numberInSurah}`}
                    onClick={handleSelectResult}
                    className="text-primary-text font-bold cursor-pointer rounded-md p-1 -m-1 hover:bg-surface-hover transition-colors"
                    aria-label={`الانتقال إلى ${displayAyah.surah?.name} الآية ${displayAyah.numberInSurah}`}
                >
                    <span className="font-quran-title">{displayAyah.surah?.name} - الآية {displayAyah.numberInSurah}</span>
                </a>

                <div className="flex items-center gap-2 flex-shrink-0">
                    <button
                        onClick={(e) => onOpenPopover(displayAyah, e.currentTarget)}
                        className="p-2 -m-2 rounded-full text-text-subtle hover:text-primary hover:bg-surface-hover transition-colors focus:outline-none focus:ring-2 focus:ring-primary/50"
                        aria-label="إجراءات الآية"
                        title="إجراءات الآية"
                    >
                        <SparklesIcon className="w-5 h-5" />
                    </button>
                </div>
            </div>
            <p
                dir={displayEdition.direction}
                aria-label={`نص الآية ${displayAyah.numberInSurah} من سورة ${displayAyah.surah?.name}`}
                className={`${quranTextClass} text-text-primary ${displayEdition.direction === 'ltr' ? 'text-left' : 'text-right'}`}
            >
               {renderAyahWithHighlight()}
            </p>
        </li>
    );
};

export default SearchResultItem;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import type { Ayah, SurahData, QuranEdition, SavedAyahItem, SavedSearchItem, FontSize, FontStyleType } from '../types';
import { SearchIcon, ClearIcon, BackspaceIcon, BackspaceReverseIcon } from './AppIcons';
import { normalizeArabicText, formatSurahNameForDisplay } from '../utils/text';
import { useSearchLogic } from '../hooks/useSearchLogic';
import { db } from '../firebase';

import DiscussionSection from './DiscussionSection';
import AyahActionPopover from './AyahActionPopover';
import SearchResultItem from './SearchResultItem';
import SearchResultsHeader from './search/SearchResultsHeader';
import SearchResultsToolbar from './search/SearchResultsToolbar';
import PhraseFilters from './search/PhraseFilters';
import NeighboringWords from './search/NeighboringWords';


interface SearchViewProps {
  query: string;
  results: Ayah[];
  onNewSearch: (word: string, sourceEdition?: string, position?: { surah: number, ayah: number, wordIndex: number }) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  onSearchComplete: () => void;
  autoOpenDiscussion?: boolean;
  displayEdition: QuranEdition;
  displayEditionData: SurahData[];
  searchEdition: string;
  fontSize: FontSize;
  fontStyle: FontStyleType;
  position?: { surah: number, ayah: number, wordIndex: number };
  simpleCleanData: SurahData[];
  onSaveAyah: (item: SavedAyahItem) => void;
  onSaveSearch: (item: SavedSearchItem) => void;
  searchType?: 'text' | 'number';
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  correctedQuery?: string;
}

export const SearchView: React.FC<SearchViewProps> = ({ 
    query, results, onNewSearch, onSearchByAyahNumber, onSearchComplete, autoOpenDiscussion, 
    displayEdition, displayEditionData, searchEdition, fontSize, fontStyle, position, 
    simpleCleanData, onSaveAyah, onSaveSearch, searchType = 'text',
    currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
    allAudioEditions, selectedAudioEdition, onAudioEditionChange,
    correctedQuery
}) => {
  const [editableQuery, setEditableQuery] = useState(query);
  const [isAllCopied, setIsAllCopied] = useState(false);

  const itemRefs = useRef<React.RefObject<HTMLLIElement>[]>([]);

  const [wordPopoverState, setWordPopoverState] = useState<{
    resultIndex: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [cachedAnalysisExists, setCachedAnalysisExists] = useState(false);
  const [pulsingWord, setPulsingWord] = useState<{ itemIndex: number; wordIndex: number } | null>(null);

  const {
    exactMatch, setExactMatch,
    visibleSuggestionsCount, handleShowMore,
    activePhraseFilter, setActivePhraseFilter,
    queryWords, isSingleWordSearch,
    phraseFilters,
    displayedResults,
    occurrencesMap, totalOccurrences,
    generalOccurrences, exactOccurrences,
    neighboringWords,
    formatResultsForExport,
  } = useSearchLogic(query, correctedQuery, results, searchType);


  const normalizedQueryForDiscussion = useMemo(() => {
    if (searchType === 'number') return `topic:ayah-number:${query}`;
    return normalizeArabicText(correctedQuery || query);
  }, [query, correctedQuery, searchType]);

  useEffect(() => { setEditableQuery(query); }, [query]);
  useEffect(() => { onSearchComplete(); }, [results, onSearchComplete]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(event.target as Node)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
        if (!(event.target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const checkAnalysisCache = async () => {
        const trimmedQuery = (correctedQuery || query).trim();
        const isSingleWord = trimmedQuery.split(/\s+/).length === 1 && trimmedQuery.length > 1;
        if (isSingleWord && searchType === 'text') {
            setCachedAnalysisExists(false);
            try {
                const snapshot = await db.collection('qran_word_analysis_cache').doc(normalizeArabicText(trimmedQuery)).collection('analyses').limit(1).get();
                if (!snapshot.empty) setCachedAnalysisExists(true);
            } catch (error) { console.error("Error checking analysis cache:", error); }
        } else {
            setCachedAnalysisExists(false);
        }
    };
    checkAnalysisCache();
  }, [query, correctedQuery, searchType]);

  itemRefs.current = displayedResults.map((_, i) => itemRefs.current[i] ?? React.createRef());

  useEffect(() => {
    if (currentlyPlayingAyahGlobalNumber) {
        const playingIndex = displayedResults.findIndex(ayah => ayah.number === currentlyPlayingAyahGlobalNumber);
        if (playingIndex !== -1 && itemRefs.current[playingIndex]?.current) {
            itemRefs.current[playingIndex].current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }
  }, [currentlyPlayingAyahGlobalNumber, displayedResults]);

  const handleJumpToOccurrence = (target: number) => {
    const occurrence = occurrencesMap[target - 1];
    if (occurrence && itemRefs.current[occurrence.itemIndex]?.current) {
        const element = itemRefs.current[occurrence.itemIndex].current;
        element?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        setPulsingWord({ itemIndex: occurrence.itemIndex, wordIndex: occurrence.wordIndex });
        setTimeout(() => setPulsingWord(null), 3000);
    }
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedQuery = editableQuery.trim();
    if (trimmedQuery && trimmedQuery !== query) onNewSearch(trimmedQuery);
  };

  const handleDeleteFirstChar = () => {
    const newQuery = editableQuery.slice(1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleDeleteLastChar = () => {
    const newQuery = editableQuery.slice(0, -1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleSaveSearch = () => {
    const queryToSave = correctedQuery || query;
    if (queryToSave) onSaveSearch({ type: 'search', id: queryToSave, query: queryToSave, createdAt: Date.now() });
  };

  const handleCopyAll = () => {
    const textToCopy = formatResultsForExport(displayEditionData);
    if (textToCopy) navigator.clipboard.writeText(textToCopy).then(() => {
        setIsAllCopied(true);
        setTimeout(() => setIsAllCopied(false), 2500);
    });
  };

  const handleDownloadAll = () => {
    const textToDownload = formatResultsForExport(displayEditionData);
    if (textToDownload) {
        const blob = new Blob([textToDownload], { type: 'text/plain;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        const safeQuery = (correctedQuery || query).replace(/[^a-zA-Z0-9-ء-ي ]/g, "").trim() || 'results';
        link.download = `qran-top-search-${safeQuery}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
    }
  };

  const handlePlayAll = () => {
    if (displayedResults.length > 0) onStartPlayback(displayedResults, selectedAudioEdition);
  };

  // --- Ayah Action Handlers ---
  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({ type: 'ayah', id: `${ayah.surah!.number}:${ayah.numberInSurah}`, surah: ayah.surah!.number, ayah: ayah.numberInSurah, text: ayah.text || '', createdAt: Date.now() });
    setActivePopover(null);
  };
  const handleCopyAyah = (ayah: Ayah) => {
    const textToCopy = `"${ayah.text || ''}" (سورة ${formatSurahNameForDisplay(ayah.surah?.name)} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };
  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah!.number);
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    if (simpleAyah?.text) onNewSearch(simpleAyah.text, 'quran-simple-clean', { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    else if (ayah.text) onNewSearch(ayah.text, displayEdition.identifier, { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    setActivePopover(null);
  };
  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = results.findIndex(a => a.number === ayah.number);
    if (startIndex !== -1) onStartPlayback(results, selectedAudioEdition, startIndex);
    setActivePopover(null);
  };

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {searchType !== 'number' && (
          <div className="mb-6">
              <form onSubmit={handleFormSubmit} className="flex-grow w-full flex items-center gap-2">
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteFirstChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من بداية الكلمة"><BackspaceIcon className="w-5 h-5" /></button>}
                <div className="relative flex-grow">
                    <input type="text" value={editableQuery} onChange={(e) => setEditableQuery(e.target.value)} placeholder="ابحث عن كلمة..." className="w-full text-xl font-bold text-primary-text-strong border-b-2 border-border-default focus:border-primary bg-transparent py-2 pr-4 pl-12 outline-none transition-colors" aria-label="كلمة البحث"/>
                    {editableQuery && (<button type="button" onClick={() => { setEditableQuery(''); onNewSearch(''); }} className="absolute left-1 top-1/2 -translate-y-1/2 p-2 text-text-muted hover:text-text-primary rounded-full" aria-label="مسح البحث"><ClearIcon className="w-5 h-5" /></button>)}
                </div>
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteLastChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من نهاية الكلمة"><BackspaceReverseIcon className="w-5 h-5" /></button>}
                <button type="submit" className="flex-shrink-0 p-3 bg-primary text-white rounded-full hover:bg-primary-hover transition-colors focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50" aria-label="بحث"><SearchIcon className="w-5 h-5" /></button>
            </form>
            <NeighboringWords neighboringWords={neighboringWords} visibleSuggestionsCount={visibleSuggestionsCount} onNeighborClick={(word) => onNewSearch(`${editableQuery.trim()} ${word}`)} onShowMore={handleShowMore}/>
          </div>
      )}

      <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
        <PhraseFilters phraseFilters={phraseFilters} activePhraseFilter={activePhraseFilter} setActivePhraseFilter={setActivePhraseFilter} resultsCount={results.length}/>
        <SearchResultsHeader 
            searchType={searchType} query={query} correctedQuery={correctedQuery}
            displayedResultsCount={displayedResults.length} resultsCount={results.length}
            isSingleWordSearch={isSingleWordSearch} generalOccurrences={generalOccurrences}
            exactOccurrences={exactOccurrences} exactMatch={exactMatch} setExactMatch={setExactMatch}
            totalOccurrences={totalOccurrences} onJumpToOccurrence={handleJumpToOccurrence}
            cachedAnalysisExists={cachedAnalysisExists} onNewSearch={onNewSearch}
        />

        {displayedResults.length > 0 && (
          <>
            <SearchResultsToolbar
                isPlaybackLoading={isPlaybackLoading} allAudioEditions={allAudioEditions}
                onPlayAll={handlePlayAll} selectedAudioEdition={selectedAudioEdition}
                onAudioEditionChange={onAudioEditionChange} searchType={searchType}
                onSaveSearch={handleSaveSearch} onCopyAll={handleCopyAll}
                isAllCopied={isAllCopied} onDownloadAll={handleDownloadAll}
            />
            <DiscussionSection topicId={normalizedQueryForDiscussion} wordForTopic={correctedQuery || query} autoOpen={autoOpenDiscussion} showAnalysisButton={isSingleWordSearch} onAnalysisClick={() => window.location.hash = `#/analysis/${encodeURIComponent(correctedQuery || query)}`}/>
          </>
        )}

        <div className="mt-6">
            {displayedResults.length > 0 ? (
                <ul className="space-y-4">
                    {displayedResults.map((ayah, index) => {
                        const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah?.number);
                        const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
                        return (
                           <SearchResultItem 
                                key={ayah.number} itemRef={itemRefs.current[index]} ayah={ayah} 
                                queryWords={searchType === 'number' ? [] : queryWords} onNewSearch={onNewSearch}
                                displayEdition={displayEdition} displayEditionData={displayEditionData} searchEdition={searchEdition}
                                fontSize={fontSize} fontStyle={fontStyle} searchType={searchType} isCurrentlyPlaying={ayah.number === currentlyPlayingAyahGlobalNumber}
                                pulsingWordIndex={pulsingWord?.itemIndex === index ? pulsingWord.wordIndex : -1} resultIndex={index}
                                simpleAyahText={simpleAyah?.text || ''}
                                onUthmaniWordClick={(e, idx, text) => { if (wordPopoverState?.resultIndex === idx) setWordPopoverState(null); else setWordPopoverState({ resultIndex: idx, simpleText: text, triggerElement: e.currentTarget }); }}
                                onOpenPopover={(ayah, triggerElement) => setActivePopover({ ayah, triggerElement })}
                            />
                       );
                    })}
                </ul>
            ) : (<div className="text-center p-10 text-lg text-text-muted">لم يتم العثور على نتائج.</div>)}
        </div>
      </main>

       {wordPopoverState && (
         <div ref={wordPopoverRef} className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return { top: `${rect.bottom + window.scrollY + 5}px`, left: `${rect.left + window.scrollX + rect.width / 2}px`, transform: 'translateX(-50%)' };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, wordIndex) => {
                const originalAyah = displayedResults[wordPopoverState.resultIndex];
                return (
                    <button key={wordIndex} onClick={() => { onNewSearch(word, 'quran-simple-clean', { surah: originalAyah.surah!.number, ayah: originalAyah.numberInSurah, wordIndex: wordIndex }); setWordPopoverState(null); }} className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors">
                        {word}
                    </button>
                );
            })}
        </div>
      )}

       {activePopover && <AyahActionPopover activePopover={activePopover} onClose={() => setActivePopover(null)} onSave={handleSaveClick} onCopy={handleCopyAyah} onSearchText={handleSearchByAyahText} onSearchNumber={onSearchByAyahNumber} onPlayFrom={handlePlayFromAyah} copiedAyah={copiedAyah} />}
    </div>
  );
};

import React, { useRef, useState, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import type { Ayah } from '../types';
import { BookmarkIcon, CopyIcon, PlayIcon, CheckIcon, SearchIcon, SparklesIcon } from './AppIcons';

const AyahActionPopover: React.FC<{
    activePopover: { ayah: Ayah; triggerElement: HTMLElement };
    onClose: () => void;
    onSave: (ayah: Ayah) => void;
    onCopy: (ayah: Ayah) => void;
    onSearchText: (ayah: Ayah) => void;
    onSearchNumber: (num: number) => void;
    onPlayFrom: (ayah: Ayah) => void;
    copiedAyah: number | null;
}> = ({ activePopover, onClose, onSave, onCopy, onSearchText, onSearchNumber, onPlayFrom, copiedAyah }) => {

    const popoverRef = useRef<HTMLDivElement>(null);
    const [style, setStyle] = useState<React.CSSProperties>({ opacity: 0, pointerEvents: 'none' });

    useLayoutEffect(() => {
        if (popoverRef.current) {
            const popover = popoverRef.current;
            const trigger = activePopover.triggerElement;

            const triggerRect = trigger.getBoundingClientRect();
            const popoverWidth = popover.offsetWidth;
            const popoverHeight = popover.offsetHeight;
            const viewportWidth = window.innerWidth;
            const margin = 10;

            let left = triggerRect.left + window.scrollX + (triggerRect.width / 2) - (popoverWidth / 2);
            if (left < margin) {
                left = margin;
            } else if (left + popoverWidth > (viewportWidth - margin)) {
                left = viewportWidth - popoverWidth - margin;
            }

            let top = triggerRect.top + window.scrollY - popoverHeight - margin;
            if (top < window.scrollY + margin) {
                top = triggerRect.bottom + window.scrollY + margin;
            }

            setStyle({
                position: 'absolute',
                top: `${top}px`,
                left: `${left}px`,
                opacity: 1,
                pointerEvents: 'auto',
            });
        }
    }, [activePopover]);

    return createPortal(
        <div 
            ref={popoverRef} 
            style={style}
            className="popover-content w-max p-1.5 bg-surface rounded-full shadow-lg border border-border-default flex items-center gap-1 z-50 animate-fade-in"
            role="dialog"
            aria-label="إجراءات الآية"
        >
            <button onClick={() => onSave(activePopover.ayah)} className="p-2.5 rounded-full text-text-subtle focus:opacity-100 hover:bg-surface-hover hover:text-primary transition-colors" title="حفظ الآية في دفتر التدبر"><BookmarkIcon className="w-5 h-5" /></button>
            <button onClick={() => onCopy(activePopover.ayah)} className="p-2.5 rounded-full text-text-subtle focus:opacity-100 hover:bg-surface-hover hover:text-primary transition-colors" title="نسخ الآية مع المرجع">
              {copiedAyah === activePopover.ayah.number ? <CheckIcon className="w-5 h-5 text-green-500" /> : <CopyIcon className="w-5 h-5" />}
            </button>
            <button onClick={() => onSearchText(activePopover.ayah)} className="p-2.5 rounded-full text-text-subtle focus:opacity-100 hover:bg-surface-hover hover:text-primary transition-colors" title="بحث عن نص الآية"><SearchIcon className="w-5 h-5" /></button>
            <button onClick={() => { onSearchNumber(activePopover.ayah.numberInSurah); onClose(); }} className="p-2.5 rounded-full text-text-subtle focus:opacity-100 hover:bg-surface-hover hover:text-primary transition-colors" title={`بحث عن كل الآيات رقم ${activePopover.ayah.numberInSurah}`}><SparklesIcon className="w-5 h-5" /></button>
            <div className="w-px h-5 bg-border-default mx-1"></div>
            <button onClick={() => onPlayFrom(activePopover.ayah)} className="p-2.5 rounded-full text-text-subtle focus:opacity-100 hover:bg-surface-hover hover:text-primary transition-colors" title="تشغيل التلاوة من هذه الآية"><PlayIcon className="w-5 h-5" /></button>
        </div>,
        document.body
      );
};

